// Normalizar la URL de imagen de cualquier proveedor
const content = $('🔧 Parsear contenido').first().json;
const imageData = $input.first().json;
const model = content.image_model;

let finalUrl = null;

if (model === 'flux' || model === 'nanoBanana') {
  // FAL.AI devuelve: { images: [{ url }] } o { image: { url } }
  finalUrl = imageData.images?.[0]?.url
          || imageData.image?.url
          || null;
} else if (model === 'ideogram') {
  // Ideogram devuelve: { data: [{ url }] }
  finalUrl = imageData.data?.[0]?.url || null;
} else if (model === 'custom') {
  finalUrl = content.image_url;
}

if (!finalUrl) {
  console.warn('⚠ No se pudo extraer URL de imagen. Respuesta:', JSON.stringify(imageData).substring(0, 300));
}

return [{ json: { ...content, final_image_url: finalUrl, image_provider_response: imageData } }];

// Handle single-post and carousel — read from correct upstream node
let d;
try {
  d = $('🗂️ Collect Image URLs').first().json;
} catch(e1) {
  try {
    d = $('🔗 Normalizar URL imagen').first().json;
  } catch(e2) {
    d = $input.first().json;
  }
}

const isCarousel = d.format === 'carousel';

const typeEmoji  = { educational:'📚', authority:'🎤', case_study:'🏆' };
const typeLabel  = { educational:'Educativo', authority:'Autoridad', case_study:'Caso de éxito' };
const modelInfo  = {
  flux:       '⚡ Flux 2 Pro',
  ideogram:   '🔤 Ideogram v3',
  nanoBanana: '🍌 Nano Banana Pro',
  custom:     '📎 Imagen propia',
};

const igPreview = d.instagram?.caption?.substring(0, 280) || 'N/A';
const fbPreview = d.facebook?.caption?.substring(0, 180) || 'N/A';
const igDots = (d.instagram?.caption?.length || 0) > 280 ? '...' : '';
const fbDots = (d.facebook?.caption?.length || 0)  > 180 ? '...' : '';

const imageStatus = isCarousel
  ? `🎠 ${d.image_urls?.length || 0} imágenes generadas (carrusel)`
  : `🖼️ ${d.final_image_url ? '✅ Imagen generada' : '⚠️ Sin imagen'}`;

const formatLine = isCarousel
  ? `\n🎠 *Formato:* Carrusel (${d.num_images} slides)`
  : '';

const msg = `🚀 *PROPULSAR CONTENT ENGINE*

${typeEmoji[d.type] || '📝'} *Tipo:* ${typeLabel[d.type] || d.type}
📌 *Tema:* ${d.topic}
${d.angle ? `🎯 *Ángulo:* ${d.angle}\n` : ''}📱 *Redes:* ${(d.platforms || []).join(', ')}
🖼️ *Imagen:* ${modelInfo[d.image_model] || d.image_model}${formatLine}

━━━━━━━━━━━━━━━━
📸 *INSTAGRAM:*
${igPreview}${igDots}

━━━━━━━━━━━━━━━━
👥 *FACEBOOK:*
${fbPreview}${fbDots}

━━━━━━━━━━━━━━━━
${imageStatus}

*¿Publicar?*
✅ *SI* para publicar
❌ *NO* para cancelar`;

return [{ json: { ...d, whatsapp_message: msg, session_id: `propulsar_${Date.now()}` } }];

// Recuperar sesión de Supabase
const phone = $json.body?.message?.from;
const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_ANON_KEY;

if (!supabaseUrl || !supabaseKey) {
  console.log('Supabase no configurado — modo testing');
  return [{ json: { approved: true, topic: 'TEST', note: 'Configurar Supabase' } }];
}

const https = require('https');
const url = new URL(`${supabaseUrl}/rest/v1/content_sessions?approval_number=eq.${phone}&status=eq.pending&order=created_at.desc&limit=1`);

const session = await new Promise((resolve, reject) => {
  const req = https.get({
    hostname: url.hostname,
    path: url.pathname + url.search,
    headers: { 'apikey': supabaseKey, 'Authorization': `Bearer ${supabaseKey}` }
  }, (res) => {
    let d = '';
    res.on('data', c => d += c);
    res.on('end', () => { try { resolve(JSON.parse(d)[0] || null); } catch { resolve(null); }});
  });
  req.on('error', reject);
});

if (!session) throw new Error('Sesión pendiente no encontrada para: ' + phone);
return [{ json: session }];

const carousel = $('🔧 Parsear prompts carrusel').first().json;
const loopItems = $input.all();

// IMG-02: Normalize and validate all image URLs
const imageUrls = loopItems.map(item => {
  const url = item.json.data?.[0]?.url || null;
  if (url && typeof url === 'string' && url.startsWith('https://')) {
    return url; // Keep full URL with auth params (exp, sig)
  }
  return null;
}).filter(Boolean);

if (imageUrls.length !== carousel.num_images) {
  throw new Error('Se generaron ' + imageUrls.length + ' imagenes, se esperaban ' + carousel.num_images + '. Faltan slides.');
}

return [{
  json: {
    instagram:       carousel.instagram,
    facebook:        carousel.facebook,
    topic:           carousel.topic,
    type:            carousel.type,
    angle:           carousel.angle || null,
    platforms:       carousel.platforms,
    image_model:     'ideogram',
    approval_number: carousel.approval_number,
    timestamp:       carousel.timestamp,
    format:          'carousel',
    num_images:      carousel.num_images,
    image_urls:      imageUrls,
    final_image_url: imageUrls[0] || null,
  }
}];

const data = $input.first().json;
const urls = data.image_urls;

return urls.map((url, idx) => ({
  json: {
    current_image_url: url,
    slide_index:       idx + 1,
    num_images:        data.num_images,
    approval_number:   data.approval_number,
    _carousel_data:    data,
  }
}));
